UPDATE coaching.exercise SET
  name = 'Wall Ball Catch-and-Freeze',
  description = 'Toss the ball to the wall or from a partner and catch it at the chest, then freeze for one count with feet, ribs, and hips organized.',
  card_summary = 'Wall Ball Catch-and-Freeze trains teaches receiving the ball softly while freezing the squat-ready posture. It belongs in Resilience when the coach wants foundation, position, and skill ownership without losing wall-ball mechanics.',
  coach_language = 'Primary subrole: landing_braking_control. Belongs in Resilience because the drill builds controlled receiving, bracing, trunk position, joint ownership, and durable positions rather than speed or conditioning. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.',
  athlete_language = 'Catch soft, freeze tall.',
  movement_family = 'Catch mechanics and position control',
  primary_phase_key = 'resilience',
  phase_subrole = 'landing_braking_control',
  primary_order_slot = 'wall_ball_catch_and_freeze',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 45,
  est_seconds_per_set = 25,
  movement_requirements = '{"primary_joint_actions":["front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"low-to-moderate","balance_demand":"low-to-moderate","coordination_demand":"moderate","impact_level":1,"expression_quality":null,"contraindication_flags":[]}'::jsonb,
  coaching_execution = '{"movement_description":"Toss the ball to the wall or from a partner and catch it at the chest, then freeze for one count with feet, ribs, and hips organized.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Toss the ball to the wall or from a partner and catch it at the chest, then freeze for one count with feet, ribs, and hips organized.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main wall-ball interval","Medicine-ball power block","Strength support block"],"pairs_well_after":["General temperature raise","Hip and ankle mobility","Front-rack breathing squat"],"good_for_sessions":["wall ball training","medicine ball conditioning"],"avoid_before":["High-fatigue burpee circuits before skill or power work","Max effort sprinting immediately after sloppy wall-ball intervals","Heavy overhead fatigue before shoulder-sensitive athletes throw"],"avoid_after":[],"do_not_use_when":[],"notes":null}'::jsonb,
