  description = 'Coach calls high/low or left/right target as the athlete starts the squat; athlete throws only to the called target and resets.',
  card_summary = 'Wall Ball Reactive Target Call trains cue-based target selection that connects seeing/hearing, throwing accuracy, and reset quality. It belongs in Movement Intelligence when the coach wants power, high-intent throwing, and output quality without losing wall-ball mechanics.',
  coach_language = 'Primary subrole: perception_action_reactive_movement. Belongs in Movement Intelligence because the main adaptation is coordination, timing, target recognition, spacing, and movement quality while the nervous system is fresh. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.',
  athlete_language = 'Hear it, hit it.',
  movement_family = 'Reactive wall-ball targeting',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'wall_ball_reactive_target_call',
  default_sets = 4,
  default_reps = NULL,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 20,
  movement_requirements = '{"primary_joint_actions":["front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"low-to-moderate","balance_demand":"low-to-moderate","coordination_demand":"high","impact_level":1,"expression_quality":null,"contraindication_flags":[]}'::jsonb,
  coaching_execution = '{"movement_description":"Coach calls high/low or left/right target as the athlete starts the squat; athlete throws only to the called target and resets.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Coach calls high/low or left/right target as the athlete starts the squat; athlete throws only to the called target and resets.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main wall-ball interval","Medicine-ball power block","Strength support block"],"pairs_well_after":["General temperature raise","Hip and ankle mobility","Front-rack breathing squat"],"good_for_sessions":["wall ball training","medicine ball conditioning"],"avoid_before":["High-fatigue burpee circuits before skill or power work","Max effort sprinting immediately after sloppy wall-ball intervals","Heavy overhead fatigue before shoulder-sensitive athletes throw"],"avoid_after":[],"do_not_use_when":[],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":[],"internal_notes":[]}'::jsonb,
  participant_structure = 'individual',
  updated_at = now()
WHERE slug = 'wall-ball-reactive-target-call';

