-- Reverse Lunge to Wall Ball Shot (reverse-lunge-to-wall-ball-shot)
UPDATE coaching.exercise SET
  name = 'Reverse Lunge to Wall Ball Shot',
  description = 'Step back into a reverse lunge while holding the ball, return to stance, and immediately perform a controlled wall-ball shot.',
  card_summary = 'Reverse Lunge to Wall Ball Shot trains unilateral strength and rhythm variation that links reverse-lunge control to a wall-ball release. It belongs in Capacity when the coach wants rotational, lateral, and multiplanar wall-ball variations without losing wall-ball mechanics.',
  coach_language = 'Primary subrole: squat_knee_dominant_strength. Belongs in Capacity because the drill builds strength, force production, tissue tolerance, and structural reserve that supports wall-ball performance. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.',
  athlete_language = 'Step, stand, throw.',
  movement_family = 'Lunge to wall-ball shot',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'reverse_lunge_to_wall_ball_shot',
  default_sets = 3,
  default_reps = 5,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 25,
  movement_requirements = '{"primary_joint_actions":["front-rack catch","overhead reach","split-stance control","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","hip stabilizers","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"moderate","balance_demand":"moderate","coordination_demand":"moderate","impact_level":1,"expression_quality":null,"contraindication_flags":[]}'::jsonb,
  coaching_execution = '{"movement_description":"Step back into a reverse lunge while holding the ball, return to stance, and immediately perform a controlled wall-ball shot.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Step back into a reverse lunge while holding the ball, return to stance, and immediately perform a controlled wall-ball shot.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Main wall-ball interval","Medicine-ball power block","Strength support block"],"pairs_well_after":["General temperature raise","Hip and ankle mobility","Front-rack breathing squat"],"good_for_sessions":["wall ball training","medicine ball conditioning"],"avoid_before":["High-fatigue burpee circuits before skill or power work","Max effort sprinting immediately after sloppy wall-ball intervals","Heavy overhead fatigue before shoulder-sensitive athletes throw"],"avoid_after":[],"do_not_use_when":[],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":[],"internal_notes":[]}'::jsonb,
