-- Wall Ball 30-30 Intervals (wall-ball-30-30-intervals)
UPDATE coaching.exercise SET
  name = 'Wall Ball 30-30 Intervals',
  description = 'Work for 30 seconds, rest for 30 seconds, and keep each interval accurate and mechanically consistent.',
  card_summary = 'Wall Ball 30-30 Intervals trains timed wall-ball intervals that train repeatable output with planned recovery. It belongs in Sustained Capacity when the coach wants sustained capacity, work-rate, and repeatability without losing wall-ball mechanics.',
  coach_language = 'Primary subrole: conditioning_intervals. Belongs in Sustained Capacity because the intended stress is repeatable wall-ball work under fatigue while maintaining posture, breathing, target accuracy, and safe mechanics. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.',
  athlete_language = 'Work hard, stay clean.',
  movement_family = 'Wall-ball work-rest intervals',
  primary_phase_key = 'sustained_capacity',
  phase_subrole = 'conditioning_intervals',
  primary_order_slot = 'wall_ball_30_30_intervals',
  default_sets = 6,
  default_reps = NULL,
  default_work_seconds = 30,
  default_rest_seconds = 30,
  est_seconds_per_set = 60,
  movement_requirements = '{"primary_joint_actions":["front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"high","balance_demand":"low-to-moderate","coordination_demand":"moderate","impact_level":1,"expression_quality":null,"contraindication_flags":[]}'::jsonb,
  coaching_execution = '{"movement_description":"Work for 30 seconds, rest for 30 seconds, and keep each interval accurate and mechanically consistent.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Work for 30 seconds, rest for 30 seconds, and keep each interval accurate and mechanically consistent.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down.","Use planned breaks before missed targets or collapsed catches appear; repeatability is the goal, not random exhaustion."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Restore cooldown","Breathing reset","Soft tissue or mobility downshift"],"pairs_well_after":["Prepare & Access","Movement Intelligence practice","Output/power work","Capacity work"],"good_for_sessions":["wall ball training","medicine ball conditioning"],"avoid_before":["Fresh speed or power after the interval","Skill learning immediately after fatigue","Any block where missed targets become acceptable"],"avoid_after":[],"do_not_use_when":[],"notes":null}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":[],"internal_notes":[]}'::jsonb,
  participant_structure = 'individual',
  updated_at = now()
WHERE slug = 'wall-ball-30-30-intervals';

