-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for wall-ball work: squat-to-throw skill, target accuracy, trunk bracing, catch mechanics, power output, and repeatable conditioning with phase-honest placement.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('medicine-ball-front-rack-breathing-squat', 'Medicine Ball Front Rack Breathing Squat improves wall-ball performance by matching the constraint that matters most: squat organization, ball path, target accuracy, trunk stiffness, catching, breathing, or repeatability. The drill creates a clear coaching problem and lets the coach progress one variable at a time: ball load, target height, squat depth, speed, rest, complexity, or total volume.', 'Belongs in Prepare & Access because the drill improves readiness, access, activation, or position ownership before higher-intent work without creating meaningful fatigue.', 'Use early in Prepare & Access before higher-intent wall-ball work.', 'Do not add enough volume or load that a readiness drill becomes fatigue work.', 'Scale by reducing ball weight, target height, squat depth, throw speed, movement complexity, total reps, work duration, or conditioning density before increasing intensity. The quality gate decides progression.'),
